// Script Continued Below
// Use this service to hover over Suspense Date field set up to handle all duration information 
// STRY0137371 - Icons to Represent Status, other task data needs can be configured to use this
// STRY0136615 - STRETCH-PLACEHOLDER- Header UI Control
// 
function dtechTaskService($document, $location, $timeout, $http, $log) {
	var self = this;

	var getBaseURL = _getBaseURL;
	var error = _error;
	var getTaskAPIURL = _getTaskAPIURL;
	var getAssignmentInformation = _getAssignmentInformation;
	var getContextMenuInformation = _getContextMenuInformation;
	var getDurationInformation = _getDurationInformation;
	var getItemMembersInformation = _getItemMembersInformation;
	var getOperationalInformation = _getOperationalInformation;
	var getResponseCommnets = _getResponseCommnets;
	var getSubTasksInformationWithList = _getSubTasksInformationWithList;
	var getTaskerFilesInformationWithFiles = _getTaskerFilesInformationWithFiles;
	var getUIActionParametersByActionName = _getUIActionParametersByActionName;
	var getUIActionParametersByGUID = _getUIActionParametersByGUID;
	var publishTask = _publishTask;
	var success = _success;
	return {
		getAssignmentInformation: getAssignmentInformation,
		getContextMenuInformation: getContextMenuInformation,
		getDurationInformation: getDurationInformation,
		getItemMembersInformation: getItemMembersInformation,
		getOperationalInformation: getOperationalInformation,
		getResponseCommnets: getResponseCommnets, 
		getSubTasksInformationWithList: getSubTasksInformationWithList,
		getTaskerFilesInformationWithFiles: getTaskerFilesInformationWithFiles,
		getUIActionParametersByActionName: getUIActionParametersByActionName,
		getUIActionParametersByGUID: getUIActionParametersByGUID,
		publishTask: publishTask
	};

	function _getBaseURL(){
		var protocol = $location.protocol();
		var host = $location.host();
		var baseURL = protocol + "://" + host;
		var port = $location.port() + '';
		if(port && port != ''){
			baseURL += ":" + port;
		}
		return baseURL;		
	}

	function _error(err){
		$log.error(JSON.stringify(err));
		return err.statusText;
	}

	function _getTaskAPIURL(){
		var baseURL = getBaseURL();
		var task_api_url = baseURL +
				"/api/x_153465_discovert/task_api/";
		return task_api_url;		
	}

	function _getAssignmentInformation(taskId){
		var task_api_url = getTaskAPIURL();
		var endPoint = task_api_url + taskId + '/getAssignmentInformation';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getContextMenuInformation(taskId){
		var task_api_url = getTaskAPIURL();
		var endPoint = task_api_url + taskId + '/getContextMenuInformation';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getDurationInformation(taskId){
		var task_api_url = getTaskAPIURL();
		var endPoint = task_api_url + taskId + '/getDurationInformation';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getItemMembersInformation(taskId){
		var task_api_url = getTaskAPIURL();
		var endPoint = task_api_url + taskId + '/getItemMembersInformation';
		var requestBody = "";
		return $http.get(endPoint).then(success, error);
	}

	function _getOperationalInformation(taskId){
		var task_api_url = getTaskAPIURL();
		var endPoint = task_api_url + taskId + '/getOperationalInformation';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getResponseCommnets(taskId){
		var task_api_url = getTaskAPIURL();
		var endPoint = task_api_url + taskId + '/getResponseCommnets';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getSubTasksInformationWithList(taskId){
		var task_api_url = getTaskAPIURL();
		var endPoint = task_api_url + taskId + '/getSubTasksInformationWithList';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getTaskerFilesInformationWithFiles(taskId){
		var task_api_url = getTaskAPIURL();
		var endPoint = task_api_url + taskId + '/getTaskerFilesInformationWithFiles';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getUIActionParametersByActionName(taskId, action_name){
		var task_api_url = getTaskAPIURL();
		var endPoint = task_api_url + taskId + '/' + action_name + '/getUIActionParametersByName';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getUIActionParametersByGUID(taskId, action_guid){
		var task_api_url = getTaskAPIURL();
		var endPoint = task_api_url + taskId + '/' + action_guid + '/getUIActionParametersByGUID';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _publishTask(metaData){
		var task_api_url = getTaskAPIURL();
		var endPoint = task_api_url + 'taskUpdate/publishTask';
		var strMetaData = JSON.stringify(metaData);
		var requestBody = strMetaData; 
		$log.log("dtechTaskService._publishTask - endPoint: " + endPoint + " - requestBody: " + requestBody);
		return $http.post(endPoint, requestBody).then(success, error);		
	}

	function _success(response){
		return response.data.result;
	}

}
